SELECT m.id AS "id", m.register_id AS "registerId", m.record_date AS "recordDate", COALESCE(m.recorded_at, m.record_date::timestamp + TIME '09:00:00') AS "recordedAt", m.metric_key AS "metricKey", m.metric_value AS "metricValue", m.unit AS "unit", m.source AS "source", m.note AS "note" FROM follow_up_health_metric m WHERE m.register_id = #{registerId}
AND m.record_date >= #{from}
AND m.record_date <= #{to}
AND m.metric_key IN
#{key}
ORDER BY m.record_date ASC, m.metric_key ASC

SELECT s.id AS "id", s.register_id AS "registerId", s.case_number AS "caseNumber", s.patient_name AS "patientName", s.week_start_date AS "weekStartDate", s.status AS "status", s.trigger_reason AS "triggerReason", s.trigger_metric_key AS "triggerMetricKey", s.patient_notified AS "patientNotified", s.creation_time AS "creationTime" FROM follow_up_interview_schedule s
s.week_start_date = #{weekStart}
AND s.status = #{status}
ORDER BY s.week_start_date DESC, s.creation_time DESC
